my initial read here is that it's a bit funky to have a stateful client, maybe something like this would make more sense? no strong pref though bc this seems pretty internal, so do as you wish!

```py
from typing import Any
from functools import lru_cache
import requests

class ModelsDevClient:
    """Client for interacting with the models.dev API."""
    
    API_URL = "https://models.dev/api.json"
    
    def __init__(self, timeout: int = 30) -> None:
        self._timeout = timeout
    
    @lru_cache(maxsize=1)
    def fetch_data(self) -> dict[str, Any]:
        """Fetch data from the API (cached)."""
        response = requests.get(self.API_URL, timeout=self._timeout)
        response.raise_for_status()
        return response.json()
    
    def get_profile_data(
        self, provider_id: str, model_id: str
    ) -> dict[str, Any] | None:
        """Get a specific model from a provider."""
        data = self.fetch_data()
        provider = data.get(provider_id)
        if provider is None:
            return None
        models = provider.get("models", {})
        return models.get(model_id)
